import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableTimes, setAvailableTimes] = useState([]);

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  const [popup, setPopup] = useState({ show: false, message: "" });

  // ================= DOCTOR =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  // ================= FEEDBACK =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  const avgRating =
    feedbacks.length > 0
      ? (feedbacks.reduce((a, b) => a + b.rating, 0) / feedbacks.length).toFixed(1)
      : 0;

  // ================= BOOK =================
  const handleBook = () => {
    if (!date || !time) {
      setPopup({ show: true, message: "Select date & time" });
      return;
    }

    navigate("/appointment", {
      state: { doctor, doctor_id, date, time },
    });
  };

  // ================= FEEDBACK =================
  const submitFeedback = () => {
    if (!rating || !comment) {
      setPopup({ show: true, message: "Fill all fields" });
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
      });
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  return (
    <div style={styles.page}>
      <Navbar />

      {/* ================= POPUP ================= */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popup}>
            <p>{popup.message}</p>
            <button onClick={() => setPopup({ show: false })}>OK</button>
          </div>
        </div>
      )}

      {/* ================= TOP SECTION ================= */}
      <div style={styles.topRow}>

        {/* LEFT - PROFILE */}
        <div style={styles.card}>
          <img
            src={doctor.image || "https://cdn-icons-png.flaticon.com/512/387/387561.png"}
            alt={doctor.name}
            style={styles.image}
          />

          <h2>{doctor.name}</h2>
          <p>👨‍⚕️ {doctor.field}</p>
          <p>🎓 {doctor.qualification}</p>
          <p>⏳ {doctor.experience} yrs</p>
          <p>⭐ {avgRating}</p>
        </div>

        {/* RIGHT - BOOKING */}
        <div style={styles.card}>
          <h3>Book Appointment</h3>

          <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            style={styles.input}
          />

          <select
            value={time}
            onChange={(e) => setTime(e.target.value)}
            style={styles.input}
          >
            <option value="">Select Time</option>
            {availableTimes.map((t, i) => (
              <option key={i}>{t}</option>
            ))}
          </select>

          <button onClick={handleBook} style={styles.bookBtn}>
            Book Appointment
          </button>
        </div>
      </div>

      {/* ================= BOTTOM - FEEDBACK ================= */}
      <div style={styles.feedbackSection}>
        <h2>Patient Reviews</h2>

        <div style={styles.feedbackForm}>
          <select value={rating} onChange={(e) => setRating(e.target.value)} style={styles.input}>
            <option value="">Rating</option>
            <option value="5">⭐⭐⭐⭐⭐</option>
            <option value="4">⭐⭐⭐⭐</option>
            <option value="3">⭐⭐⭐</option>
            <option value="2">⭐⭐</option>
            <option value="1">⭐</option>
          </select>

          <textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            placeholder="Write feedback..."
            style={styles.textarea}
          />

          <button onClick={submitFeedback} style={styles.reviewBtn}>
            Submit Review
          </button>
        </div>

        {/* REVIEWS */}
        <div style={styles.reviewList}>
          {feedbacks.map((f, i) => (
            <div key={i} style={styles.reviewCard}>
              <b>{f.user_name}</b>
              <p>{"⭐".repeat(f.rating)}</p>
              <p>{f.comment}</p>
            </div>
          ))}
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* ================= STYLES ================= */
const styles = {
  page: { background: "#f4f6f9", minHeight: "100vh" },

  topRow: {
    display: "flex",
    gap: "20px",
    padding: "30px",
  },

  card: {
    flex: 1,
    background: "#fff",
    padding: "25px",
    borderRadius: "12px",
    boxShadow: "0 5px 15px rgba(0,0,0,0.08)",
    textAlign: "center",
  },

  image: {
    width: "130px",
    height: "130px",
    borderRadius: "50%",
  },

  input: {
    width: "100%",
    padding: "10px",
    marginTop: "10px",
    borderRadius: "8px",
    border: "1px solid #ddd",
  },

  textarea: {
    width: "100%",
    height: "80px",
    marginTop: "10px",
    borderRadius: "8px",
    padding: "10px",
  },

  bookBtn: {
    width: "100%",
    marginTop: "15px",
    padding: "10px",
    background: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: "8px",
  },

  reviewBtn: {
    width: "100%",
    marginTop: "10px",
    padding: "10px",
    background: "#27ae60",
    color: "#fff",
    border: "none",
    borderRadius: "8px",
  },

  feedbackSection: {
    margin: "30px",
    background: "#fff",
    padding: "20px",
    borderRadius: "12px",
  },

  feedbackForm: {
    display: "flex",
    flexDirection: "column",
    gap: "10px",
    marginBottom: "20px",
  },

  reviewList: {
    marginTop: "10px",
  },

  reviewCard: {
    background: "#f1f1f1",
    padding: "10px",
    borderRadius: "8px",
    marginTop: "10px",
  },

  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    width: "100%",
    height: "100%",
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  popup: {
    background: "#fff",
    padding: "20px",
    borderRadius: "10px",
  },

  loading: {
    textAlign: "center",
    marginTop: "50px",
  },
};
